// Sestavíme historii konverzace do textu pro AI
const incoming = $('Webhook (zpráva z webu)').first().json.body;
const conversationId = incoming.conversationId;
const name = incoming.name || 'Neznámý';
const email = incoming.email || '';
const userMessage = incoming.message || '';

// Všechny předchozí řádky z Google Sheets pro tuto konverzaci
const rows = $input.all().map(i => i.json).filter(r => r.conversationId === conversationId);

let history = '';
for (const r of rows) {
  if (r.role && r.text) {
    history += (r.role === 'user' ? 'Uživatel: ' : 'Asistent: ') + r.text + '\n';
  }
}

return [{
  json: {
    conversationId,
    name,
    email,
    userMessage,
    history: history.trim(),
    isFirstMessage: rows.length === 0
  }
}];

// Zpracujeme odpověď z Gemini a zjistíme, zda je potřeba eskalace
function extractText(value) {
  if (!value) return '';
  if (typeof value === 'string') return value;
  if (Array.isArray(value)) return value.map(extractText).filter(Boolean).join(' ');
  if (typeof value === 'object') {
    if (value.text) return extractText(value.text);
    if (value.output) return extractText(value.output);
    if (value.content) return extractText(value.content);
    if (value.response) return extractText(value.response);
    if (value.parts) return extractText(value.parts);
    if (value.candidates) return extractText(value.candidates);
  }
  return '';
}

let reply = extractText($json).trim();

const needsEscalation = reply.includes('[ESKALACE]');
reply = reply.replace(/\[ESKALACE\]/g, '').trim();

if (!reply) {
  reply = 'Děkujeme za zprávu. Předávám ji týmu NUMINA a brzy se vám ozveme s konkrétní odpovědí.';
}

const ctx = $('Sestav kontext').first().json;

return [{
  json: {
    conversationId: ctx.conversationId,
    name: ctx.name,
    email: ctx.email,
    userMessage: ctx.userMessage,
    reply,
    needsEscalation,
    isFirstMessage: ctx.isFirstMessage
  }
}];

